sections.body:
To use the [C Driver](c) to create a MongoDB Search index, define the
search index in your application and call the
`mongoc_collection_command_simple()` method.

> **Note:** The MongoDB Search index management methods run asynchronously. The
> driver methods can return before confirming that they ran
> successfully. To determine the current status of the search indexes,
> run an aggregation operation with the `$listSearchIndexes` pipeline
> stage.

Create One Search Index

The following sample application specifies the `createSearchIndexes`
command to define a search index. Then, the application converts the command and search index
information to BSON (Binary Javascript Object Notation) and passes this information to the `mongoc_collection_command_simple()`
method to create the search index. To learn more, see [index definitions](ref-index-definitions).

```c
#include <mongoc/mongoc.h>
#include <stdlib.h>

int main (void)
{
    mongoc_client_t *client = NULL;
    mongoc_collection_t *collection = NULL;
    mongoc_database_t *database = NULL;
    bson_error_t error;
    bson_t cmd = BSON_INITIALIZER;
    bool ok = true;

    mongoc_init();

    // Connect to your Atlas deployment
    client = mongoc_client_new("<connectionString>");
    if (!client) {
        fprintf(stderr, "Failed to create a MongoDB client.\n");
        ok = false;
        goto cleanup;
    }

    // Access your database and collection
    database = mongoc_client_get_database(client, "<databaseName>");
    collection = mongoc_database_get_collection(database, "<collectionName>");

    // Specify the command and the new index
    const char *cmd_str = BSON_STR({
        "createSearchIndexes" : "<collectionName>",
        "indexes" : [ {
            "name" : "<indexName>",
            "definition" : {
                "analyzer": "<indexAnalyzer>", 
                "searchAnalyzer": "<queryAnalyzer>", 
                "mappings": { 
                    "dynamic": <boolean>, 
                    "fields": { <fieldDefinition> } 
                },
                "numPartitions": <integer>,
                "analyzers": [ <customAnalyzer> ],
                "storedSource": <boolean> | {
                    <storedSourceDefinition>
                },
                "synonyms": [
                    {
                        <synonymMappingDefinition>
                    }
                ] 
            }
	    } ]
	});

    // Convert your command to BSON
    if (!bson_init_from_json(&cmd, cmd_str, -1, &error)) {
        fprintf(stderr, "Failed to parse command: %s\n", error.message);
        ok = false;
        goto cleanup;
    }

    // Create the MongoDB Search index by running the command
    if (!mongoc_collection_command_simple (collection, &cmd, NULL, NULL, &error)) {
        fprintf(stderr, "Failed to run createSearchIndexes: %s\n", error.message);
        ok = false;
        goto cleanup;
    }
    printf ("Index created!\n");

cleanup:
   mongoc_collection_destroy (collection);
   mongoc_client_destroy (client);
   mongoc_database_destroy (database);
   bson_destroy (&cmd);
   mongoc_cleanup ();
   return ok ? EXIT_SUCCESS : EXIT_FAILURE;
}
```

Create Multiple Search Indexes

The following sample application uses the `createSearchIndexes` command to
define multiple search indexes. Then, the application converts the command and search index
information to BSON (Binary Javascript Object Notation) and passes this information to the `mongoc_collection_command_simple()`
method to create the search index. To learn more, see [index definitions](ref-index-definitions).

```c
#include <mongoc/mongoc.h>
#include <stdlib.h>

int main (void)
{
    mongoc_client_t *client = NULL;
    mongoc_collection_t *collection = NULL;
    mongoc_database_t *database = NULL;
    bson_error_t error;
    bson_t cmd = BSON_INITIALIZER;
    bool ok = true;

    mongoc_init();

    // Connect to your Atlas deployment
    client = mongoc_client_new("<connectionString>");
    if (!client) {
        fprintf(stderr, "Failed to create a MongoDB client.\n");
        ok = false;
        goto cleanup;
    }

    // Access your database and collection
    database = mongoc_client_get_database(client, "<databaseName>");
    collection = mongoc_database_get_collection(database, "<collectionName>");

    // Specify the command and the new indexes
    const char *cmd_str = BSON_STR({
        "createSearchIndexes" : "<collectionName>",
        "indexes" : [{
            // Add your search index definition fields here
            "name" : "<firstIndexName>"
        },
        {
            // Add your search index definition fields here
            "name" : "<secondIndexName>"
        }]
    });

    // Convert your command to BSON
    if (!bson_init_from_json(&cmd, cmd_str, -1, &error)) {
        fprintf(stderr, "Failed to parse command: %s\n", error.message);
        ok = false;
        goto cleanup;
    }

    // Create the MongoDB Search indexes by running the command
    if (!mongoc_collection_command_simple (collection, &cmd, NULL, NULL, &error)) {
        fprintf(stderr, "Failed to run createSearchIndexes: %s\n", error.message);
        ok = false;
        goto cleanup;
    }
    printf ("Indexes created!\n");

cleanup:
   mongoc_collection_destroy (collection);
   mongoc_client_destroy (client);
   mongoc_database_destroy (database);
   bson_destroy (&cmd);
   mongoc_cleanup ();
   return ok ? EXIT_SUCCESS : EXIT_FAILURE;
}
```

- Your Atlas connection string. To learn more, see [Driver](connect-via-driver).

- The database and collection for which you want to create the index.

- The name of your index. If you omit the index name, MongoDB Search names the index `default`.

- The search index definition. To learn more, see [index definitions](ref-index-definitions).

```shell
gcc -o create-index create-index.c $(pkg-config --libs --cflags libmongoc-1.0)
./create-index
```

